import React from 'react';
import { Play, Heart, ExternalLink } from 'lucide-react';
import { getGenreStyle } from '../utils/helpers';

export default function TrackList({ tracks, playTrack, toggleLike, isLiked, currentTrack, isPlaying }) {
  if (!tracks || tracks.length === 0) return null;

  return (
    <div className="track-list">
      <div className="track-list-header">
        <span>#</span>
        <span>Title</span>
        <span>Genre</span>
        <span className="track-bpm-col">BPM</span>
        <span style={{ textAlign: 'right' }}>Listen</span>
      </div>
      {tracks.map((track, i) => {
        const style = getGenreStyle(track.genre);
        const active = currentTrack?.id === track.id;
        return (
          <div
            key={track.id}
            className={`track-row ${active ? 'active' : ''}`}
            onDoubleClick={() => playTrack(track, tracks)}
          >
            <div className="track-num" style={{ color: active ? '#1db954' : undefined }}>
              <span className="track-num">{i + 1}</span>
              <span className="track-play-icon" onClick={() => playTrack(track, tracks)}>
                <Play size={16} fill="white" />
              </span>
            </div>
            <div className="track-info">
              <div className="track-art" style={{ '--c1': style.c1, '--c2': style.c2 }}>
                {style.emoji}
              </div>
              <div className="track-text">
                <div className={`track-title ${active ? 'active' : ''}`}>{track.title}</div>
                <div className="track-artist">{track.artist}</div>
              </div>
            </div>
            <div className="track-genre" style={{ textTransform: 'capitalize' }}>{track.genre}</div>
            <div className="track-bpm">{track.tempo} BPM</div>
            <div className="track-actions">
              <button
                className={`icon-btn ${isLiked(track.id) ? 'liked' : ''}`}
                onClick={(e) => { e.stopPropagation(); toggleLike(track); }}
              >
                <Heart size={16} fill={isLiked(track.id) ? 'currentColor' : 'none'} />
              </button>
              {track.streaming && (
                <a
                  href={track.streaming.spotify}
                  target="_blank"
                  rel="noreferrer"
                  className="icon-btn"
                  onClick={(e) => e.stopPropagation()}
                  title="Open on Spotify"
                >
                  <ExternalLink size={14} />
                </a>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}
